const input=document.querySelector(".login__input"),button=document.querySelector(".play"),form=document.querySelector(".login-form"),validateInput=({target:t})=>{if(t.value.length>3){button.removeAttribute("disabled");return}button.setAttribute("disabled","")},handleSubmit=t=>{t.preventDefault(),localStorage.setItem("player",input.value),window.location="play.html"};input.addEventListener("input",validateInput),form.addEventListener("submit",handleSubmit);